// buildSignedCommandPathsContext assembles the v4 `signed_command_paths`
// block. CRITICAL: never include token literals here. Audience and scopes
// come from the static fleetAPIAudience / fleetScopes constants and (when
// a Fleet access token is present and parseable) from non-secret JWT
// claims; the raw token bytes never leave decodeJWTClaims. Expiry is the
// already-persisted expiry timestamp, not the token itself.
func buildSignedCommandPathsContext() *agentContextSignedCmdPaths {
	out := &agentContextSignedCmdPaths{
		PerVehicle: []agentContextVehiclePathEntry{},
	}

	// Fleet availability + non-secret claim metadata.
	fleetTokPresent := false
	if cfg, err := config.Load(""); err == nil && cfg != nil {
		ft := cfg.FleetTokens()
		fleetTokPresent = ft.AccessToken != "" || os.Getenv("TESLA_FLEET_TOKEN") != ""
		out.Fleet.Available = fleetTokPresent
		if fleetTokPresent {
			// Audience source precedence: decoded JWT aud claim (best
			// effort, never echoes the token), then the static
			// fleetAPIAudience constant.
			tok := firstNonEmpty(os.Getenv("TESLA_FLEET_TOKEN"), ft.AccessToken)
			if tok != "" {
				if aud, scopes, jerr := decodeJWTClaims(tok); jerr == nil {
					if len(aud) > 0 {
						out.Fleet.Audience = aud[0]
					}
					if scopes != "" {
						out.Fleet.Scopes = splitScopes(scopes)
					}
				}
			}
			if out.Fleet.Audience == "" {
				out.Fleet.Audience = fleetAPIAudience
			}
			if len(out.Fleet.Scopes) == 0 {
				out.Fleet.Scopes = splitScopes(fleetScopes)
			}
			if !ft.TokenExpiry.IsZero() {
				out.Fleet.Expiry = ft.TokenExpiry.UTC().Format(time.RFC3339)
			}
		}
	}

	// Hermes relay liveness + port. Reads the PID/port files written by
	// `tesla relay start`. No network call here.
	if paths, err := newRelayPaths(); err == nil {
		_, port, alive := readRelayState(paths)
		out.Hermes.Running = alive
		if alive {
			out.Hermes.Port = port
		}
	}

	return out
}

// splitScopes turns the OAuth space-separated scope string into a slice.
// Empty scope -> empty slice (not nil) so JSON serialization stays
// deterministic across runs.
func splitScopes(s string) []string {
	parts := []string{}
	for _, p := range strings.Fields(s) {
		if p != "" {
			parts = append(parts, p)
		}
	}
	return parts
}

